def compute_venues(stadiums, games):
    import re, math
    def pc(s):
        out=[]
        for m in re.finditer(r'(\d+\.\d+)°\s*([NSEW])', s):
            v=float(m.group(1));  out.append(round(-v if m.group(2) in 'SW' else v,4))
        if len(out)>=2: return out[:2]
        out=[]
        for m in re.finditer(r'(\d+)°(\d+)\x27([\d.]+)"?\s*([NSEW])', s):
            v=int(m.group(1))+int(m.group(2))/60+float(m.group(3))/3600
            out.append(round(-v if m.group(4) in 'SW' else v,4))
        return out[:2]
    GEO={}
    for s in (stadiums or []):
        c=pc(s.get("coords",""))
        if len(c)==2:
            GEO[s["city"]]={"city":s["city"],"name":s.get("name",""),"cc":s.get("cc",""),
                            "cap":s.get("capacity",0),"lat":c[0],"lng":c[1]}
    def dist(a,b):
        R=6371.0; la1,lo1,la2,lo2=map(math.radians,[a["lat"],a["lng"],b["lat"],b["lng"]])
        h=math.sin((la2-la1)/2)**2+math.cos(la1)*math.cos(la2)*math.sin((lo2-lo1)/2)**2
        return int(round(2*R*math.asin(math.sqrt(h))))
    from collections import defaultdict
    bycode=defaultdict(list)
    for fs,meta in META_GRP.items():
        city=meta.get("gr"); dt=meta.get("dt","")
        if city not in GEO: continue
        for code in fs: bycode[code].append((dt,city))
    ROUTES={}
    for code,lst in bycode.items():
        lst.sort()
        cities=[c for _,c in lst]
        km=sum(dist(GEO[cities[i-1]],GEO[cities[i]]) for i in range(1,len(cities)))
        ROUTES[code]={"cities":cities,"km":km}
    return {"geo":list(GEO.values()),"routes":ROUTES,"contours":CONTOURS}

# ---------- projeção de probabilidades (Monte Carlo sobre o Elo) ----------
def _poisson(l):
    L=math.exp(-l); k=0; p=1.0
    while True:
        k+=1; p*=random.random()
        if p<=L: return k-1
def _goals(ra,rb):
    return _poisson(min(1.35*math.exp((ra-rb)/280),4.5)), _poisson(min(1.35*math.exp((rb-ra)/280),4.5))
def _adv(ra,rb): return 1/(1+10**((rb-ra)/400))
def _koslot(spec,pg,alloc,RES):
    if "wn" in spec: return pg[spec["wn"]][0]
    if "ru" in spec: return pg[spec["ru"]][1]
    if "th" in spec:
        g=alloc.get(spec["th"]) if alloc else None
        return pg[g][2] if g else None
    if "win" in spec: r=RES.get(spec["win"]); return r["w"] if r else None
    if "lose" in spec:
        r=RES.get(spec["lose"]); return (r["b"] if r["a"]==r["w"] else r["a"]) if r else None

def monte_carlo(games, alloc_map, n=8000):
    random.seed(42)   # estabilidade: mesmas %s entre builds; só mudam quando entra resultado novo
    realres={}
    for m in games:
        if m.get("r"): realres[frozenset((m["h"],m["a"]))]=(m["h"],m["gh"],m["a"],m["ga"])
    real_ko={frozenset((k["h"],k["a"])):k["w"] for k in KO_REAL if k.get("w")}
    reach={c:{"g":0,"s":0,"f":0,"t":0} for c in NAME}
    for _ in range(n):
        pg={}; thirds=[]
        for g,ts in GR.items():
            P={t:0 for t in ts}; GF={t:0 for t in ts}; GA={t:0 for t in ts}
            for a,b in itertools.combinations(ts,2):
                rr=realres.get(frozenset((a,b)))
                if rr:
                    h,gh,aw,ga_=rr; ga,gb=(gh,ga_) if h==a else (ga_,gh)
                else: ga,gb=_goals(ELO[a],ELO[b])
                GF[a]+=ga;GA[a]+=gb;GF[b]+=gb;GA[b]+=ga
                if ga>gb:P[a]+=3
                elif gb>ga:P[b]+=3
                else:P[a]+=1;P[b]+=1
            order=sorted(ts,key=lambda t:(-P[t],-(GF[t]-GA[t]),-GF[t],-ELO.get(t,1500),random.random()))
            pg[g]=order; t=order[2]; thirds.append((g,P[t],GF[t]-GA[t],GF[t],ELO.get(t,1500)))
        thirds.sort(key=lambda x:(-x[1],-x[2],-x[3],-x[4]))
        alloc=alloc_map.get("".join(sorted(x[0] for x in thirds[:8])))
        RES={}
        for i in sorted(KO):
            a=_koslot(KO[i]["a"],pg,alloc,RES); b=_koslot(KO[i]["b"],pg,alloc,RES)
            if not a: w=b
            elif not b: w=a
            elif frozenset((a,b)) in real_ko: w=real_ko[frozenset((a,b))]
            else: w = a if random.random()<_adv(ELO.get(a,1500),ELO.get(b,1500)) else b
            RES[i]={"a":a,"b":b,"w":w}
        for i in range(73,89):
            for s in ("a","b"):
                if RES[i][s]: reach[RES[i][s]]["g"]+=1
        for i in (101,102):
            for s in ("a","b"):
                if RES[i][s]: reach[RES[i][s]]["s"]+=1
        for s in ("a","b"):
            if RES[104][s]: reach[RES[104][s]]["f"]+=1
        if RES[104]["w"]: reach[RES[104]["w"]]["t"]+=1
    PROB={}
    for c in NAME:
        r=reach[c]
        PROB[c]={"elo":ELO.get(c,1500),"g":round(r["g"]/n*100),"s":round(r["s"]/n*100),
                 "f":round(r["f"]/n*100),"t":round(r["t"]/n*100,1)}
    return PROB

# ---------- montar / calcular ----------
def build():
    real=load_seed(); real.update(fetch_results())   # openfootball tem prioridade sobre o seed
    games=[]
    for g,ts in GR.items():
        for a,b in itertools.combinations(ts,2):
            if (a,b) in real:   H,A=a,b; gh,ga=real[(a,b)]; rr=True
            elif (b,a) in real: H,A=b,a; gh,ga=real[(b,a)]; rr=True
            else: H,A,s=pred_score(a,b); gh,ga=s; rr=False
            rd=ROUNDS.get((H,A)) or ROUNDS.get((A,H))
            meta=META_GRP.get(frozenset((H,A))) or {}
            _d,_h=fmt_when_brt(meta.get("dt",""),meta.get("tm",""))
            games.append({"g":g,"h":H,"a":A,"gh":gh,"ga":ga,"r":rr,"rd":rd,
                          "dt":_d,"hr":_h,"gr":meta.get("gr","")})
    return games

def standings(games):
    tab={}
    for g,ts in GR.items():
        st={t:{"P":0,"W":0,"D":0,"L":0,"GF":0,"GA":0} for t in ts}
        for m in games:
            if m["g"]!=g: continue
            h,a,gh,ga=m["h"],m["a"],m["gh"],m["ga"]
            st[h]["GF"]+=gh; st[h]["GA"]+=ga; st[a]["GF"]+=ga; st[a]["GA"]+=gh
            if gh>ga: st[h]["P"]+=3;st[h]["W"]+=1;st[a]["L"]+=1
            elif gh<ga: st[a]["P"]+=3;st[a]["W"]+=1;st[h]["L"]+=1
            else: st[h]["P"]+=1;st[a]["P"]+=1;st[h]["D"]+=1;st[a]["D"]+=1
        order=sorted(ts,key=lambda t:(-st[t]["P"],-(st[t]["GF"]-st[t]["GA"]),-st[t]["GF"],-F[t]))
        tab[g]=(order,st)
    return tab

def main():
    games=build()
    tab=standings(games)
    real_n=sum(1 for m in games if m["r"])
    # --- arquivos extras do openfootball (sede / elencos / seleções) ---
    stadiums=aslist(fetch_json(OF_STADIUMS),"stadiums")
    squads  =aslist(fetch_json(OF_SQUADS),  "squads")
    teams   =aslist(fetch_json(OF_TEAMS),   "teams")
    sbc={s["city"]:s for s in stadiums} if stadiums else {}
    # enriquecer cada jogo de grupo com estádio + país
    for m in games:
        v=venue_of(m.get("gr",""), sbc)
        m["vn"]=v["vn"]; m["co"]=v["co"]; m["cf"]=CFLAG.get(v["cc"],"")
    # sede/data dos jogos do mata-mata (indexados pelo número 73..104)
    VENUE_KO={}
    for num,meta in META_KO.items():
        v=venue_of(meta.get("gr",""), sbc)
        _d,_h=fmt_when_brt(meta.get("dt",""),meta.get("tm",""))
        VENUE_KO[str(num)]={"dt":_d,"hr":_h,"vn":v["vn"],"co":v["co"],"cf":CFLAG.get(v["cc"],"")}
    STATS=compute_stats(games, squads, stadiums, teams)
    BRASIL=compute_brasil(games)
    VENUES=compute_venues(stadiums, games)
    PROFILES=compute_profiles(games, squads)
    # retrospecto: histórico vai até 2025 (martj42); os jogos de 2026 vêm do openfootball (mesma fonte da tabela do app)
    ALL_FULL={k:list(v) for k,v in ALL.items()}
    for m in games:
        if not m.get("r"): continue
        x,y=sorted([m["h"],m["a"]]); k=f"{x}-{y}"
        gx,gy=(m["gh"],m["ga"]) if x==m["h"] else (m["ga"],m["gh"])
        ALL_FULL.setdefault(k,[]).insert(0,[2026,0,gx,gy,"G",""])
    # REALLIST p/ rodape
    rg=[m for m in games if m["r"]]; rg.sort(key=lambda m:m["g"])
    reallist=" · ".join(f"{NAME[m['h']]} {m['gh']}–{m['ga']} {NAME[m['a']]}" for m in rg) or "(nenhum ainda)"
    now=datetime.datetime.now(TZ) if TZ else datetime.datetime.utcnow()
    asof=now.strftime("%d/%m/%Y %H:%M")+(" (Brasília)" if TZ else " UTC")
    # injetar no template
    ALLOC=json.load(open(os.path.join(HERE,"third_alloc.json"),encoding="utf-8"))
    PROB=monte_carlo(games, ALLOC, n=8000)
    ESPN_ALIAS={"Türkiye":"Turkey","United States":"USA","Korea Republic":"South Korea",
                "IR Iran":"Iran","Côte d'Ivoire":"Ivory Coast","Czechia":"Czech Republic",
                "Cape Verde":"Cabo Verde","Curacao":"Curaçao","Bosnia and Herzegovina":"Bosnia & Herzegovina"}
    ENPT={}
    for eng,code in OF_NAMES.items(): ENPT[eng]={"pt":NAME.get(code,eng),"fl":FLAG.get(code,"")}
    for al,eng in ESPN_ALIAS.items():
        c=OF_NAMES.get(eng)
        if c: ENPT[al]={"pt":NAME.get(c,al),"fl":FLAG.get(c,"")}
    DATA={"F":F,"GR":GR,"NAME":NAME,"FLAG":FLAG,"GAMES":games,
          "PRED_PHASES":original_phases(ALLOC),"KO_REAL":KO_REAL,
          "VENUE_KO":VENUE_KO,"BRASIL":BRASIL,"NUMBERS":STATS,"VENUES":VENUES,"PROFILES":PROFILES,"ALL":ALL_FULL,"PROB":PROB,"ENPT":ENPT}
    tpl=open(os.path.join(HERE,"template2.html"),encoding="utf-8").read()
    html=(tpl.replace("/*__DATA__*/",json.dumps(DATA,ensure_ascii=False,separators=(",",":")))
             .replace("/*__ALLOC__*/",json.dumps(ALLOC,ensure_ascii=False,separators=(",",":")))
             .replace("__REALLIST__",reallist).replace("__ASOF__",asof))
    site=os.path.join(HERE,"site")
    os.makedirs(site,exist_ok=True)
    open(os.path.join(site,"index.html"),"w",encoding="utf-8").write(html)
    # arquivos de indexação (SEO)
    open(os.path.join(site,"robots.txt"),"w",encoding="utf-8").write(
        "User-agent: *\nAllow: /\nSitemap: https://evandroback.github.io/Copa-2026/sitemap.xml\n")
    today=now.strftime("%Y-%m-%d")
    open(os.path.join(site,"sitemap.xml"),"w",encoding="utf-8").write(
        '<?xml version="1.0" encoding="UTF-8"?>\n'
        '<urlset xmlns="http://www.sitemaps.org/schemas/sitemap/0.9">\n'
        '  <url>\n    <loc>https://evandroback.github.io/Copa-2026/</loc>\n'
        f'    <lastmod>{today}</lastmod>\n    <changefreq>hourly</changefreq>\n    <priority>1.0</priority>\n'
        '  </url>\n</urlset>\n')
    print(f"[ok] site gerado — {real_n} jogos reais — {len(STATS.get('sections',[]))} seções de números — {asof}")

if __name__=="__main__":
    main()
